  const riskLevel = CATEGORY_RISK[category];
  const { min, max } = RISK_RETURN_RANGES[riskLevel];
  const expectedReturn = deterministicValue(apiProduct.id, min, max);

  return {
    id: apiProduct.id,
    name: apiProduct.title.length > 45
      ? apiProduct.title.substring(0, 45) + '…'
      : apiProduct.title,
