 * @returns {Object} portfolio stats
 */
export function calculatePortfolioStats(items) {
  if (!items || items.length === 0) {
    return {
      totalInvested: 0,
      weightedReturn: 0,
      riskDistribution: { low: 0, medium: 0, high: 0 },
      categoryDistribution: {},
      diversificationScore: 0,
      isHighRiskWarning: false,
    };
  }

  const totalInvested = items.reduce((sum, i) => sum + Number(i.amount), 0);

  // Weighted expected return
  const weightedReturn = totalInvested === 0 ? 0 :
    items.reduce((sum, i) => sum + (Number(i.amount) / totalInvested) * i.product.expectedReturn, 0);

  // Risk distribution (% of portfolio)
  const riskDist = { low: 0, medium: 0, high: 0 };
  items.forEach(i => {
    const pct = totalInvested > 0 ? (Number(i.amount) / totalInvested) * 100 : 0;
    riskDist[i.product.riskLevel] = (riskDist[i.product.riskLevel] || 0) + pct;
  });

