  return {
    totalInvested,
    weightedReturn: parseFloat(weightedReturn.toFixed(2)),
    riskDistribution: {
      low:    parseFloat(riskDist.low.toFixed(1)),
      medium: parseFloat(riskDist.medium.toFixed(1)),
      high:   parseFloat(riskDist.high.toFixed(1)),
